const origem = $node["Lat e Long da Origem1"].json.results?.[0]?.geometry?.location;
const destino = $node["Lat e Long do Destino1"].json.results?.[0]?.geometry?.location;

if (!origem || !destino) {
  throw new Error('Erro ao obter coordenadas');
}

return [{
  json: {
    origem_lat: origem.lat,
    origem_lng: origem.lng,
    destino_lat: destino.lat,
    destino_lng: destino.lng
  }
}];

const route = items[0].json.routes?.[0];

if (!route) {
  return [{
    json: {
      distancia_km: 0,
      pedagios: 0,
      erro: true
    }
  }];
}

const distancia_km = (route.distanceMeters / 1000) * 1.073;

let pedagio = 0;

const toll = route.travelAdvisory?.tollInfo?.estimatedPrice?.[0];

if (toll) {
  const units = Number(toll.units || 0);
  const nanos = Number(toll.nanos || 0) / 1e9;

  pedagio = units + nanos;
}

return [{
  json: {
    distancia_km: Number(distancia_km.toFixed(2)),
    pedagios: Number(pedagio.toFixed(2))
  }
}];

const data = items[0].json;

const custo_combustivel = Number(data.custo_combustivel || 0);
const pedagio_total = Number(data.pedagio_total || 0);

const custo_total_base = custo_combustivel + pedagio_total;
const custo_total_com_imposto = custo_total_base / 0.60;

return [
  {
    json: {
      ...data,
      custo_total_base: Number(custo_total_base.toFixed(2)),
      custo_total_com_imposto: Number(custo_total_com_imposto.toFixed(2))
    }
  }
];

const data = $node["Organiza dados1"].json;

// ===============================
// 🔹 Peso real (sempre obrigatório)
// ===============================
const peso_real = Number(
  String(data.peso || '0')
    .replace(/[^\d.,]/g, '')
    .replace(',', '.')
) || 0;

// ===============================
// 🔹 Parser de dimensão (seguro)
// ===============================
const parseDim = (dimStr) => {
  if (!dimStr || typeof dimStr !== 'string') return null;

  const limpo = dimStr
    .toLowerCase()
    .replace(/cm/g, '')
    .replace(/\s/g, '')
    .replace(/,/g, '.');

  if (limpo.includes('indisponivel') || limpo.includes('indisponível')) {
    return null;
  }

  const partes = limpo.split('x').map(v => Number(v));

  if (partes.length !== 3 || partes.some(n => isNaN(n) || n <= 0)) {
    return null;
  }

  return partes;
};

// ===============================
// 🔹 Cálculo do volume
// ===============================
let volume_m3 = 0;
let quantidade_volumes_total = 0;
let temDimensaoValida = false;

if (Array.isArray(data.dimensoes)) {
  for (const item of data.dimensoes) {
    const qtd = Number(item.qtd) || 1;
    const parsed = parseDim(item.dim);

    if (parsed) {
      const [c, l, a] = parsed;
      volume_m3 += (c * l * a / 1_000_000) * qtd;
      quantidade_volumes_total += qtd;
      temDimensaoValida = true;
    }
  }
}

// ===============================
// 🔹 Peso cúbico (só se tiver dimensão válida)
// ===============================
let peso_cubico = 0;

if (temDimensaoValida) {
  peso_cubico = volume_m3 * 300;
}

// ===============================
// 🔹 Peso considerado
// ===============================
const peso_considerado = Math.max(peso_real, peso_cubico);

// ===============================
// 🔹 Escolha do veículo
// ===============================
let veiculo = "Indefinido";

if (peso_considerado <= 650)        veiculo = "Fiorino";
else if (peso_considerado <= 1500)  veiculo = "Van";
else if (peso_considerado <= 3000)  veiculo = "HR / VUC";
else if (peso_considerado <= 4000)  veiculo = "3/4";
else if (peso_considerado <= 6000)  veiculo = "Toco";
else                                 veiculo = "Truck";

return [{
  json: {
    volume_total_m3:    Number(volume_m3.toFixed(3)),
    quantidade_volumes: quantidade_volumes_total,
    peso_real:          Number(peso_real.toFixed(2)),
    peso_cubico:        Number(peso_cubico.toFixed(2)),
    peso_considerado:   Number(peso_considerado.toFixed(2)),
    veiculo_sugerido:   veiculo,
    observacao: temDimensaoValida 
      ? "Cálculo com dimensões"
      : "Cálculo apenas com peso real (dimensões ausentes ou inválidas)"
  }
}];

const data = items[0].json;

const veiculo = data.veiculo_sugerido || "Indefinido";
const pedagio_ida_2_eixos = Number(data.pedagios || 0);

// ===============================
// 🔹 Mapeamento de eixos por veículo
// ATUALIZADO: Fiorino e Van = 2 eixos,
// HR/VUC e 3/4 = 2 eixos, Toco = 2 eixos, Truck = 3 eixos
// ===============================
const eixos_por_veiculo = {
  "Fiorino": 2,
  "Van": 2,
  "HR / VUC": 2,
  "3/4": 2,
  "Toco": 2,
  "Truck": 3
};

const eixos = eixos_por_veiculo[veiculo] || 2;

const pedagio_por_eixo = pedagio_ida_2_eixos / 2;
const pedagio_ida_ajustado = pedagio_por_eixo * eixos;

return [
  {
    json: {
      ...data,
      eixos_veiculo: eixos,
      pedagio_ida_ajustado: Number(pedagio_ida_ajustado.toFixed(2))
    }
  }
];

const distancia_km = Number($json.distancia_km || 0);
const pedagios_ida = Number($json.pedagio_ida_ajustado || 0);
const veiculo = $json.veiculo_sugerido || "Indefinido";

const km_total = distancia_km * 2;
const pedagio_total = pedagios_ida * 2;

// ===============================
// 🔹 Custo operacional fixo por km (por veículo)
// Inclui: combustível + manutenção + depreciação + motorista + seguro + outros
// Fiorino e Van: valores definidos pela operação AVLOG
// HR/VUC em diante: calculados com acréscimo progressivo sobre combustível
// ===============================
const custo_por_km = {
  "Fiorino":  1.50,
  "Van":      2.50,
  "HR / VUC": 3.43,
  "3/4":      4.28,
  "Toco":     5.40,
  "Truck":    7.47
};

const custo_km = custo_por_km[veiculo] || 2.60; // fallback para Van se veículo indefinido
const custo_operacional = Number((km_total * custo_km).toFixed(2));

return [{
  json: {
    distancia_km:       Number(distancia_km.toFixed(2)),
    km_total:           Number(km_total.toFixed(2)),
    pedagios_ida:       Number(pedagios_ida.toFixed(2)),
    pedagio_total:      Number(pedagio_total.toFixed(2)),
    custo_km_veiculo:   custo_km,
    custo_combustivel:  custo_operacional, // mantém o nome para compatibilidade com nós seguintes
    litros_consumidos:  0                  // zerado pois não se aplica mais ao novo modelo
  }
}];

// Mapeamento de abreviações e variações comuns para nomes completos
const CIDADES = {
