const normalizaCidade = (valor) => {
  if (!valor) return valor;

  // Remove barra e normaliza separadores (ex: "Coronel Pacheco/MG" → "Coronel Pacheco, MG")
  let normalizado = String(valor)
    .trim()
    .replace(/\s*\/\s*/g, ', ')   // "Cidade/MG" → "Cidade, MG"
    .replace(/\s*-\s*([A-Z]{2})$/, ', $1');  // "Cidade - MG" → "Cidade, MG"

  // Verifica se a versão em lowercase bate com o mapeamento
  const chave = normalizado.toLowerCase().trim();
  if (CIDADES[chave]) {
    return CIDADES[chave];
  }

  return normalizado;
};

const origem  = normalizaCidade($input.first().json.origem);
const destino = normalizaCidade($input.first().json.destino);

return [{
  json: {
    ...$input.first().json,
    origem,
    destino
  }
}];

// Nó: Code (JavaScript) — n8n
// Lê dinamicamente todas as linhas da planilha
// Novos clientes adicionados na tabela entram automaticamente, sem alterar o código

const rows = $input.all().map(item => item.json);

const tabela = { INTERIOR: [], CAPITAL: [] };

function parsearCliente(nome, taxa, acima_de, kg_limite, kg_excedente, frete_minimo) {
  // Ignora linhas vazias ou de cabeçalho
  if (!nome || nome === "CLIENTE" || nome.toString().trim() === "") return null;

  // Normaliza a taxa (aceita 0.013, "1.3%", "2.0%", etc.)
  let taxaNormalizada;
  if (typeof taxa === "string" && taxa.includes("%")) {
    taxaNormalizada = parseFloat(taxa.replace("%", "").trim()) / 100;
  } else {
    taxaNormalizada = parseFloat(taxa);
  }

  // Normaliza o acima_de (aceita número ou "TODAS NOTAS" / "TODAS")
  let acimaNormalizado;
  if (typeof acima_de === "string" && acima_de.toUpperCase().includes("TODAS")) {
    acimaNormalizado = "TODAS";
  } else {
    acimaNormalizado = parseFloat(acima_de);
  }

  // Normaliza o kg_limite (aceita "50 Kg", "70 kg", "100KG", 0, etc.)
  let kgLimiteNormalizado;
  if (typeof kg_limite === "string") {
    kgLimiteNormalizado = parseFloat(kg_limite.replace(/[^0-9.]/g, "")) || 0;
  } else {
    kgLimiteNormalizado = parseFloat(kg_limite) || 0;
  }

  return {
    cliente:       nome.toString().trim(),
    taxa:          taxaNormalizada,
    acima_de:      acimaNormalizado,
    kg_limite:     kgLimiteNormalizado,
    kg_excedente:  parseFloat(kg_excedente) || 0,
    frete_minimo:  parseFloat(frete_minimo) || 0
  };
}

for (const row of rows) {
  // Processa coluna INTERIOR
  const interior = parsearCliente(
    row["INTERIOR"],
    row["col_2"],
    row["col_3"],
    row["col_4"],
    row["col_5"],
    row["col_6"]
  );
  if (interior) tabela.INTERIOR.push(interior);

  // Processa coluna CAPITAL
  const capital = parsearCliente(
    row["CAPITAL"],
    row["col_8"],
    row["col_9"],
    row["col_10"],
    row["col_11"],
    row["col_12"]
  );
  if (capital) tabela.CAPITAL.push(capital);
}

return [{ json: { tabela_clientes: tabela } }];

// ===============================
// 🔹 Entrada
// ===============================
const entrada = $('Organiza dados1').first().json;
const tabela_clientes = $('Organiza a saída da tabela').first().json.tabela_clientes;

const cliente_nome_raw = String(entrada.cliente || '').trim();
const cliente_nome     = cliente_nome_raw.toUpperCase();

const tipo_tabela      = String(entrada.tipo_tabela || 'INTERIOR').toUpperCase();
const valor_mercadoria = Number(
  String(entrada.valor_mercadoria || '0')
    .replace(/[^\d.,]/g, '')
    .replace(',', '.')
);
const peso_informado = Number(
  String(entrada.peso || '0')
    .replace(/[^\d.,]/g, '')
    .replace(',', '.')
);
const dedicado = String(entrada.dedicado || 'nao').toLowerCase().trim();

const lista = tabela_clientes?.[tipo_tabela] || [];

// ===============================
// 🔴 REGRA: CLIENTE AVULSO
// ===============================
if (cliente_nome === "AVULSO") {

  // ✅ permitido → dedicado
  if (dedicado === "sim") {
    return [{
      json: {
        cliente: "AVULSO",
        tipo_tabela: tipo_tabela,

        peso_informado: 0,
        peso_considerado: 0,

        valor_mercadoria: Number(valor_mercadoria.toFixed(2)),

        frete_ad_valorem: 0,
        frete_base: 0,
        tem_excedente: false,
        excedente: 0,
        frete_final: 0,

        dedicado: "sim",
        observacao: "Cliente avulso - frete dedicado tratado fora"
      }
    }];
  }

  // ❌ inválido
  return [{
    json: {
      erro_frete: "Cliente AVULSO sem frete dedicado."
    }
  }];
}

// ===============================
// 🔹 Normalização
// ===============================
const normalizar = (str) => {
  return String(str || '')
    .toLowerCase()
    .normalize("NFD")
    .replace(/[\u0300-\u036f]/g, "")
    .replace(/\b(ltda|me|epp|sa|s\/a)\b/g, '')
    .replace(/[^a-z0-9\s]/g, '')
    .replace(/\s+/g, ' ')
    .trim();
};

const nomeEntrada = normalizar(cliente_nome_raw);

// ===============================
// 🔹 Similaridade
// ===============================
const scoreSimilaridade = (a, b) => {
  const palavrasA = a.split(' ');
  const palavrasB = b.split(' ');

  let match = 0;

  for (const p of palavrasA) {
    if (palavrasB.includes(p)) match++;
  }

  return match / Math.max(palavrasA.length, palavrasB.length);
};

// ===============================
// 🔹 MATCH POR REDUÇÃO
// ===============================
let cliente = null;
let partes = nomeEntrada.split(' ');

for (let i = partes.length; i > 0; i--) {
  const tentativa = partes.slice(0, i).join(' ');

  cliente = lista.find(c => normalizar(c.cliente) === tentativa);

  if (cliente) break;
}

// ===============================
// 🔹 MATCH POR INCLUSÃO
// ===============================
if (!cliente) {
  cliente = lista.find(c => {
    const nomeTabela = normalizar(c.cliente);
    return nomeEntrada.includes(nomeTabela);
  });
}

// ===============================
// 🔹 FALLBACK SCORE
// ===============================
let melhorScore = 0;

if (!cliente) {
  for (const c of lista) {
    const nomeTabela = normalizar(c.cliente);
    const score = scoreSimilaridade(nomeEntrada, nomeTabela);

    if (score > melhorScore) {
      melhorScore = score;
      cliente = c;
    }
  }
}

// ===============================
// 🔹 FALLBACK FINAL
// ===============================
if (!cliente) {
  cliente = lista[0];
}

// ===============================
// 🔹 Peso considerado
// ===============================
const peso_taxado_final = Number($('Sugestão de veículo1').first().json.peso_considerado || 0);
const peso_considerado  = Math.max(peso_informado, peso_taxado_final);

// ===============================
// 🔹 Frete
// ===============================
const frete_ad_valorem = valor_mercadoria * cliente.taxa;
const frete_base = Math.max(frete_ad_valorem, cliente.frete_minimo);

let excedente = 0;
let tem_excedente = false;

if (cliente.kg_limite > 0 && cliente.acima_de !== 'TODAS') {
  if (peso_considerado > cliente.kg_limite) {
    excedente = (peso_considerado - cliente.kg_limite) * cliente.kg_excedente;
    tem_excedente = true;
  }
}

const frete_final = frete_base + excedente;

// ===============================
// 🔹 Retorno
// ===============================
return [{
  json: {
    cliente:            cliente.cliente,
    cliente_original:   cliente_nome_raw,
    tipo_tabela:        tipo_tabela,

    taxa_aplicada:      cliente.taxa,
    frete_minimo:       cliente.frete_minimo,
    kg_limite:          cliente.kg_limite,
    kg_excedente_valor: cliente.kg_excedente,
    acima_de:           String(cliente.acima_de),

    peso_informado:     Number(peso_informado.toFixed(2)),
    peso_considerado:   Number(peso_considerado.toFixed(2)),

    valor_mercadoria:   Number(valor_mercadoria.toFixed(2)),
    frete_ad_valorem:   Number(frete_ad_valorem.toFixed(2)),
    frete_base:         Number(frete_base.toFixed(2)),
    tem_excedente:      tem_excedente,
    excedente:          Number(excedente.toFixed(2)),
    frete_final:        Number(frete_final.toFixed(2)),

    dedicado:           dedicado,
    score_match:        Number(melhorScore.toFixed(2))
  }
}];

// Nó tipo: Code (substitui o Set atual para poder calcular valor_total dinamicamente)

const rota   = $('Cálculo final (imposto)1').first().json;
const frete  = $('Cálculo de frete (ad valorem + excedente)').first().json;

// Se houve erro na busca do cliente, devolve o erro direto
if (frete.erro_frete) {
  return [{ json: { erro_frete: frete.erro_frete } }];
}

const eh_dedicado            = frete.dedicado === 'sim';
const custo_total_com_imposto = Number(rota.custo_total_com_imposto || 0);
const valor_total             = eh_dedicado
  ? frete.frete_final + custo_total_com_imposto
  : frete.frete_final;

return [{
  json: {
    // ── rota ──────────────────────────────────────
    distancia_km_ida_e_volta:  rota.km_total,
    pedagios_ida_e_volta:      rota.pedagio_total,
    veiculo_sugerido:          $('Sugestão de veículo1').first().json.veiculo_sugerido,
    custo_combustivel:         rota.custo_combustivel,
    custo_total_base:          rota.custo_total_base,
    custo_total_com_imposto:   rota.custo_total_com_imposto,

    // ── peso ──────────────────────────────────────
    peso_informado:            frete.peso_informado,
    peso_taxado_final:         $('Sugestão de veículo1').first().json.peso_considerado,
    peso_considerado:          frete.peso_considerado,

    // ── tabela do cliente ─────────────────────────
    cliente:                   frete.cliente,
    tipo_tabela:               frete.tipo_tabela,
    taxa_aplicada:             frete.taxa_aplicada,
    frete_minimo:              frete.frete_minimo,
    kg_limite:                 frete.kg_limite,
    kg_excedente_valor:        frete.kg_excedente_valor,
    acima_de:                  frete.acima_de,

    // ── memória de cálculo ────────────────────────
    valor_mercadoria:          frete.valor_mercadoria,
    frete_ad_valorem:          frete.frete_ad_valorem,
    frete_base:                frete.frete_base,
    tem_excedente:             frete.tem_excedente,
    excedente:                 frete.excedente,
    frete_final:               frete.frete_final,
    eh_dedicado:               eh_dedicado,
    valor_total:               Number(valor_total.toFixed(2))
  }
}];
